CREATE TABLE J09C_temp AS
SELECT * FROM decision_table
WHERE TOUR LIKE 'J09C%';

UPDATE J09C_temp
SET ENTSCHEIDUNG = 'KSA'
WHERE HAUS IN (
  SELECT HAUS FROM (
    SELECT HAUS, COUNT(DISTINCT EQUNR) AS eq_count
    FROM J09C_temp
    GROUP BY HAUS
  )
  WHERE eq_count < 3
);

UPDATE J09C_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HAUS IN (
  SELECT HAUS FROM (
    SELECT HAUS, COUNT(DISTINCT EQUNR) AS eq_count
    FROM J09C_temp
    GROUP BY HAUS
  )
  WHERE eq_count >= 3
);

UPDATE J09C_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 = 0;

UPDATE J09C_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 BETWEEN 500 AND 599;

UPDATE J09C_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 BETWEEN 900 AND 999;

SELECT COUNT(*) AS cnt
FROM J09C_temp jt
JOIN sales_master sm ON jt.EQUNR = sm.EQUNR;
